#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(:standard);
use File::Basename;
use File::Spec::Functions qw(catfile);

my $log_dir = "/var/log/myapp";

print header('text/html; charset=UTF-8');
print start_html(-title => 'Log Viewer', 
                 -style => {'src' => '/style.css'});

my $logfile = param('logfile') || '';

print h1('Web Log Viewer');

if ($logfile eq '') {
    print p('No log file specified.');
    print p('Please provide a logfile parameter.');
    print end_html();
    exit;
}

my $basename = basename($logfile);
$basename =~ s/[^a-zA-Z0-9._-]//g;

if ($basename eq '' || $basename ne $logfile) {
    print p('Invalid log file name.');
    print end_html();
    exit;
}

my $allowed_pattern = qr/^[a-zA-Z0-9._-]+\.log$/;
unless ($basename =~ $allowed_pattern) {
    print p('Log file must have .log extension and contain only alphanumeric characters, dots, underscores, and hyphens.');
    print end_html();
    exit;
}

my $filepath = catfile($log_dir, $basename);

unless (-e $filepath) {
    print p("Log file does not exist: " . escapeHTML($basename));
    print end_html();
    exit;
}

unless (-f $filepath) {
    print p("Not a regular file: " . escapeHTML($basename));
    print end_html();
    exit;
}

unless (-r $filepath) {
    print p("Cannot read log file: " . escapeHTML($basename));
    print end_html();
    exit;
}

my $realpath = Cwd::realpath($filepath);
my $real_log_dir = Cwd::realpath($log_dir);

unless (defined $realpath && defined $real_log_dir && 
        index($realpath, $real_log_dir) == 0) {
    print p('Access denied: Path traversal detected.');
    print end_html();
    exit;
}

print h2("Log File: " . escapeHTML($basename));
print start_pre();

open(FH, '<', $filepath) or do {
    print "Error opening file: $!";
    print end_pre();
    print end_html();
    exit;
};

while (my $line = <FH>) {
    print escapeHTML($line);
}

close(FH);

print end_pre();
print end_html();